void testing(char text[]){
    int i,j,len;
    len=strlen(text);
    for(i=0,j=len-1;i<len;i++,j--) {
        if(text[i]==text[j]) {
            text[i]='*';
            text[j]='#';
        }
    }
}
int main(){
    char str[]="0010111101";
    testing(str);
    printf("%s", str);
}

