#include <stdio.h>
int power(int base, int exp, int result) {
    if(exp == 0) return result;
    return power(base, exp - 1, result * base);
}

int main() {
    printf("%d", power(2, 4, 1));
    return 0;
}

#include <stdio.h>
int main() {
    int n = 3, num = 1;

    for (int i = 1; i <= n; i++) {
        if (i % 2 != 0) {
            for (int j = i; j <= n; j++) {
                printf("%d ", num++);
            }
        } else {
            num += n - 1;
            for (int j = i; j <= n; j++) {
                printf("%d ", num--);
            }
            num += n + 1;
        }
    }
    printf("\n");

    return 0;
}

