#include <stdio.h>
int run(int r) {
    printf("Welcome to the running community!\n");
    if (r % 2) {
        return r + 101;
    }
    else {
        return r + 100;
    }
    return r;
    printf("Good job! Go ahead. \n");
}
int fun() {
    printf("Life is too short, so we need to learn with fun!\n");
    return run(29 % 3);
}
int explore(int a) {
    printf("You can explore the coding world. Let's start!\n");
    a = a++ + --a + ++a + a--;
    printf("What's your update? %d\n", a);
    a = run(a);
    return a;
    int okay = fun();
    printf("Good job! You did it. fun function value is: %d \n", okay);
}
int main() {
    int batch = 65;
    int experience = explore(batch);
    printf("Back to reality %d\n", batch);
    if(experience < 205){
        printf("The experience value is %d\n", experience + 11);
    }
    else {
        printf("The experience value is %d\n", experience - 11);
    }
    return 0;
}

#include <stdio.h>
int main() {
    int i, j, k = 2, sum = 0;
    for (i = 0; i <= 4; i++) {
        j = i;
        while (j <= 5) {
            if ((i * j + k) % 3 == 0) {
                sum += i + j;
                k++;
                break;
            }
            else if ((i + j + k) % 2 == 0) {
                sum += j - i;
                j += 2;
            }
            else {
                sum += i * k;
                j++;
                k--;
            }
        }
        printf("Ongoing sum: %d\n", sum);
    }
    printf("Final sum: %d\n", sum);
    return 0;
}

#include <stdio.h>
int puzzle(int n) {
    if (n <= 0) {
        printf("X ");
        return 1;
    }

    printf("%d ", n);
    int value = puzzle(n - 1);
    int result = value + n;
    printf("%d ", result);
    return result;
}

int main() {
    int final = puzzle(4);
    printf("\nFinal value = %d\n", final);
    return 0;
}

