    {
        if (a % 2 == 0) 
            b++;
        else 
            c++;
        
        printf("%d %d %d\n", a, b, c);
        
        if (a == 8) 
            a = 3;
        else if (a == 3) 
            a = 6;
        else if (a == 6) 
            a = 9;
        else if (a == 9) 
            a = 0;
    } while (a != 0);
    
    return 0;
}

#include <stdio.h>
int main()
{
    int n = 9;
    int i = 1;
    int j;
    for (j = i * 7; i < n / 2 && i != j; j = j - 1 + i)
    {
        j = j - 2 + i;
        printf("i=%d, j=%d\n", i, j);
        do {
            j += 3, n--;
        } while (j % 2 != 0);
        if (i == 1) continue;
        i++;
    }
    return 0;
}

