#include <stdio.h>

int bar(int x) {
    if (x & 2 && x > 0)
        printf("%05d ", x);

    if (x < 0 || x > 10)
        return -x;

    int ret = 0;
    switch (x) {
        default:
            ret += bar((x-- > 4) - 3) + bar(x);
        case 4:
            ret -= bar(x + 13);
            break;
        case 0:
            ret %= bar(x - 2);
    }
    return ret;
}

int main() {
    int y = 0, n = 8;

    puts("What the heck is this puts!");
    printf("Recursion means %#4o!\n", n);

    if (((1 << 4) & n) == 1)
        puts("No!");

    for (n = ~n;; y++) {
        puts("Should I call?");
        if (y % 3)
            continue;

        printf("bar(%d)=%d\n", y, n = bar(y));
        if (y > n)
            break;

        printf("Milestone#%02d\n", y);
    }

    printf("Well done Mr Recursion!");
    return 0;
}

