void calculate(int n, int p, int A[]){
    int prod = 0;
    for (int i = 1; i<=n; i++){
        for (int j = 1; j <= i*i; j++){
            prod *= pow(i,j);
        }
    }

    for(int m = 2; m <= p; m++){
        if(A[m] < 100 ){
            break;
        }

        prod = prod * A[m];
    }

    cout<<prod<<endl;
}

