bool connectDots(int arr[], int n){
    int numberOfDots = 0;
    for(int i=0; i<n; i++){
        if(arr[i]&1){
            for(int j=i+1; j<=n-1; j++){
                numberOfDots++;
            }
            for(int j=0; j<=i; j++){
                numberOfDots *= 2;
            }
        }
        int j = 1;
        while(j<=n){
            numberOfDots+=j;
            j = j * 2;
        }
    }
    return (numberOfDots&1);
}

