void func1(int A[], int B[], int n, int m) {
    int sumA = 0;
    for (int i = 0; i < n; i++) {
        sumA = sumA + A[i];
    }

    int sumB = 0;
    for (int i = 0; i < m; i++) {
        sumB = sumB + B[i];
    }

    int count = 0;

    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            if (A[i] * A[i] > B[j] || sumA > sumB) {
                count++;
            } else {
                break;
            }
        }
    }
}

