class FlowerRescue {
    static FlowerRescue bloomAgain;
    String flower;

    FlowerRescue(String flower) {
        this.flower = flower;
        System.out.println("Simple and clear: " + flower);
    }

    public void finalize() {
        System.out.println(flower + " couldn't survived!!");
    }

    void ref() {
        FlowerRescue obj3 = new FlowerRescue("SunFlower");
        bloomAgain = this;
        return obj3;
    }

    public static void main(String[] args) {
        FlowerRescue obj = new FlowerRescue("Lotus");
        FlowerRescue obj2 = new FlowerRescue("Tulip");
        obj2.ref();
        obj = null;
        new FlowerRescue("Orchid");
        System.gc();

        if (bloomAgain != null)
            System.out.println("Fun, generic, and meaningful!");
    }
}

public class ThreadBasic extends Thread {
