    public static void main(String[] args) {
        for (int i = 1; i <= 5; i++) {
            for (int j = 1; j <= 5; j++) {
                if (j == i) {
                    break; // Stops inner loop immediately
                }
                if (i + j == 6) {
                    continue; // Skips printing for this specific j
                }
                System.out.print("*");
            }
            System.out.println(); // New line after each row
        }
    }
}

