class Citizen {
    String action;

    Citizen(String action) {
        this.action = action;
    }

    void serve(Citizen c) {
        c.action += " -> Educate"; // Changes the object property directly
        c = new Citizen("Learn Skills"); // Reassigning 'c' locally (loses link to the original object)
        c.action += " -> Work Hard"; // This only affects the new local object
    }

    void contribute(Citizen c) {
        c.action += " -> Volunteer"; // Changes the object property directly
        c = new Citizen("Inspire Others"); // Reassigning 'c' locally
        c.action += " -> Lead"; // This only affects the new local object
    }

    void showAction() {
        System.out.println(action);
    }
}

