public class GExample {
    public static void main(String[] args) {
        try {
            System.out.println("Try Start");
            try {
                String s = null;
                System.out.println(s.length()); // Throws NullPointerException
                int x = 10 / 0; // This line is never reached
            } catch (ArithmeticException e) {
                System.out.println("Inner Catch: ArithmeticException");
            }
            System.out.println("After Inner Try-Catch"); // This line is never reached
        } catch (ArithmeticException e) {
            System.out.println("Outer Catch: ArithmeticException");
        } catch (Exception e) {
            System.out.println("Outer Catch: Exception");
        } finally {
            return; // Terminates the method immediately
        }
    }
}

public class Pattern2 {
    public static void main(String[] args) {
        int n = 5;
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                // Draws the 'X' shape
                if (i == j || i + j == n - 1) {
                    System.out.print("*");
                    continue;
                }
                // Fills the bottom area with '#'
                if (i + j > n - 1) {
                    System.out.print("#");
                } else {
                    System.out.print(" ");
                }
            }
            System.out.println();
        }
    }
}

