class Base {
    private int x = 5;
    protected int y = 10;
    Base() {
        show();
        System.out.println("Base Constructor");
    }
    private void show() {
        System.out.println("Base show(): x = " + x);
    }
    protected void print() {
        System.out.println("Base print(): y = " + y);
    }
}

class Derived extends Base {
    private int x = 20;
    protected int y = 30;

    Derived() {
        y++;
        System.out.println("Derived Constructor");
    }
    protected void show() {
        System.out.println("Derived show(): x = " + x);
    }
    protected void print() {
        super.print();
        System.out.println("Derived print(): y = " + y);
    }
    void display() {
        System.out.println("Display: x = " + x + ", y = " + y);
    }
}

public class Main {
    public static void main(String[] args) {
        Base b = new Derived();
        b.print();
        Derived d = (Derived) b;
        d.display();
    }
}

