class Super {
    void print(int a) {
        System.out.println("super: " + a);
    }
    void print() {
        System.out.println("inside sub");
    }
}

class Sub extends Super {
    void print(int a) {
        System.out.println("sub: " + a);
    }
    void print() {
        System.out.println("inside subsub");
    }
}

class SubSub extends Sub {
    void print(int a) {
        System.out.println("super: " + a);
    }
    void print() {
        System.out.println("inside sub");
    }
}

class Main {
    public static void main(String[] args) {
        Super x = new Super();
        Sub y = new Sub();
        SubSub z = new SubSub();

        x.print(2);
        x = y;
        x.print();
        y = z;
        y.print(3);
        z.print();
    }
}

