class Student { 
    public String name; 
    public int id; 
    Student(String name,int id){ 
        this.name = name; 
        this.id = id; 
    } 
 
    public Student getStudent(Student s1){ 
           s1 = new Student("Rahim",101); 
           return s1; 
    } 
} 
class Main{ 
    public static void main(String[] args) { 
        Student s1 = new Student("Karim",102); 
