class StackInt {
    private int max_size = 5;
    private int cursize = 0;
    Integer stack_arr[] = new Integer[max_size];

    void push(Integer val) {
        if (cursize >= max_size) {
            System.out.println("Status >>> Stack Full");
        } else {
            stack_arr[cursize] = val;
            cursize++;
        }
    }

    Integer pop() {
        Integer top_value = 0;
        if (cursize == 0) {
            System.out.println("Status >>> Empty Stack");
        } else {
            top_value = stack_arr[cursize - 1];
            cursize--;
        }
        return top_value;
    }
}

class StackString {
    private int max_size = 5;
    private int cursize = 0;
    String stack_arr[] = new String[max_size];

    void push(String val) {
        if (cursize >= max_size) {
            System.out.println("Status >>> Stack Full");
        } else {
            stack_arr[cursize] = val;
            cursize++;
        }
    }

    String pop() {
        String top_value = "0";
        if (cursize == 0) {
            System.out.println("Status >>> Empty Stack");
        } else {
            top_value = stack_arr[cursize - 1];
            cursize--;
        }
        return top_value;
    }
}

