class MyStack {
    private int idx = 0;
    private char[] data = new char[6];

    public synchronized void push(char c) {
        while (idx == data.length) { // stack full
            try {
                this.wait();
            } catch (InterruptedException e) {
                e.printStackTrace();
            }
        }
        data[idx] = c;
        idx++;
        this.notify();
    }

    public synchronized char pop() {
        while (idx == 0) { // stack empty
            try {
                this.wait();
            } catch (InterruptedException e) {
                e.printStackTrace();
            }
        }
        idx--;
        char c = data[idx];
        this.notify();
        return c;
    }
}

class Producer implements Runnable {
    private MyStack stack;

    public Producer(MyStack s) {
        stack = s;
    }

    public void run() {
        char c;
        for (int i = 0; i < 50; i++) {
            c = (char)(Math.random() * 26 + 'A');
            stack.push(c);
            System.out.println("Producer: " + c);
            try {
                Thread.sleep(50); // slow down a bit
            } catch (InterruptedException e) {
                e.printStackTrace();
            }
        }
    }
}

class Consumer implements Runnable {
    private MyStack stack;

    public Consumer(MyStack s) {
        stack = s;
    }

    public void run() {
        char c;
        for (int i = 0; i < 50; i++) {
            c = stack.pop();
            System.out.println("Consumer: " + c);
            try {
                Thread.sleep(100); // slow down a bit
            } catch (InterruptedException e) {
                e.printStackTrace();
            }
        }
    }
}

